+    it('should return failure for empty recipient', async () => {
+      const payload = makePayload({ recipient: '' });
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('cannot be empty');
+    });
+
+    it('should return failure when transport throws', async () => {
+      const failingTransport: SmsTransport = {
+        send: async () => {
+          throw new Error('SMS gateway unavailable');
+        },
+      };
+      const failAdapter = new SmsNotificationAdapter(defaultConfig, failingTransport);
+
+      const result = await failAdapter.send(makePayload());
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('SMS gateway unavailable');
+    });
+  });
+
+  describe('getSentMessages / clearSentMessages', () => {
+    it('should return sent messages from in-memory transport', async () => {
+      await adapter.send(makePayload());
+      expect(adapter.getSentMessages()).toHaveLength(1);
+    });
+
+    it('should clear sent messages', async () => {
+      await adapter.send(makePayload());
+      adapter.clearSentMessages();
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should return empty array when using non-InMemory transport', () => {
+      const customTransport: SmsTransport = {
+        send: async () => ({ messageId: 'x' }),
+      };
+      const customAdapter = new SmsNotificationAdapter(defaultConfig, customTransport);
+      expect(customAdapter.getSentMessages()).toEqual([]);
+    });
+  });
+
+  describe('getTransport', () => {
+    it('should return the underlying transport', () => {
+      expect(adapter.getTransport()).toBe(transport);
+    });
+  });
+});

