/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel.
 * Features:
 * - Phone number validation (E.164 format)
 * - Message formatting with truncation for SMS length limits
 * - Pluggable transport layer (inject real SMS provider for production)
 *
 * Architecture constraint: All adapters must implement NotificationAdapter
 * and be registered with NotificationService via registerAdapter().
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SmsConfig {
  /** Default sender ID or phone number */
  from: string;
  /** Maximum message length (default: 160) */
  maxMessageLength?: number;
}

/**
 * Rendered SMS content ready for transport.
 */
export interface RenderedSms {
  from: string;
  to: string;
  body: string;
}

/**
 * Transport interface for sending SMS messages.
 * Implement this with your SMS provider (Twilio, SNS, etc.)
 */
export interface SmsTransport {
  send(sms: RenderedSms): Promise<{ messageId: string }>;
}

/**
 * In-memory transport that captures sent SMS messages. Useful for testing and development.
 */
export class InMemorySmsTransport implements SmsTransport {
  private sent: RenderedSms[] = [];

  async send(sms: RenderedSms): Promise<{ messageId: string }> {
    this.sent.push(sms);
    return { messageId: `sms-${this.sent.length}` };
  }

  getSentMessages(): RenderedSms[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

const PHONE_REGEX = /^\+[1-9]\d{6,14}$/;

/**
 * Validate that a string looks like an E.164 phone number.
 */
export function isValidPhoneNumber(phone: string): boolean {
  if (!phone || phone.length > 16) return false;
  return PHONE_REGEX.test(phone);
}

export class SmsNotificationAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private transport: SmsTransport;
  private config: SmsConfig;

  constructor(config: SmsConfig, transport?: SmsTransport) {
    this.config = config;
    this.transport = transport ?? new InMemorySmsTransport();
  }

  /**
   * Validate and resolve the recipient phone number.
   * Returns the validated phone number or throws if invalid.
   */
  resolveRecipient(recipient: string): string {
    const trimmed = recipient.trim();

    if (!trimmed) {
      throw new Error('SMS recipient cannot be empty');
    }

    if (trimmed.length > 16) {
      throw new Error('SMS recipient exceeds maximum length of 16');
    }

    if (!isValidPhoneNumber(trimmed)) {
      throw new Error(`Invalid phone number: ${trimmed}`);
    }

    return trimmed;
  }

  /**
   * Format a notification payload into an SMS message.
   * Truncates the body to fit within the configured max message length.
   */
  formatMessage(payload: NotificationPayload): RenderedSms {
    const maxLen = this.config.maxMessageLength ?? 160;
    const prefix = `${payload.subject}: `;
    const availableLen = maxLen - prefix.length;

    let body: string;
    if (availableLen <= 0) {
      body = payload.subject.slice(0, maxLen);
    } else if (payload.body.length > availableLen) {
      body = prefix + payload.body.slice(0, availableLen - 3) + '...';
    } else {
      body = prefix + payload.body;
    }

    return {
      from: this.config.from,
      to: payload.recipient,
      body,
    };
  }

  /**
   * Send a notification via SMS.
   *
   * 1. Validates the recipient phone number
   * 2. Formats the SMS message
   * 3. Sends via the configured transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const resolvedRecipient = this.resolveRecipient(payload.recipient);
      const resolvedPayload = { ...payload, recipient: resolvedRecipient };

      const sms = this.formatMessage(resolvedPayload);

      this.logger.info(
        `Sending SMS to ${sms.to}: "${payload.subject}"`,
      );

      await this.transport.send(sms);

      this.logger.info(`SMS delivered to ${sms.to}`);

      return {
        notificationId: payload.id,
        channel: 'sms',
        success: true,
        deliveredAt: new Date(),
      };
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send SMS for ${payload.id}: ${message}`);

      return {
        notificationId: payload.id,
        channel: 'sms',
        success: false,
        error: message,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get all messages sent through this adapter (only works with InMemorySmsTransport).
   */
  getSentMessages(): RenderedSms[] {
    if (this.transport instanceof InMemorySmsTransport) {
      return this.transport.getSentMessages();
    }
    return [];
  }

  /**
   * Clear sent messages (only works with InMemorySmsTransport).
   */
  clearSentMessages(): void {
    if (this.transport instanceof InMemorySmsTransport) {
      this.transport.clear();
    }
  }

  /**
   * Get the underlying transport (useful for testing).
   */
  getTransport(): SmsTransport {
    return this.transport;
  }
}

