      const rendered = adapter.formatMessage(payload);

      expect(rendered.from).toBe('+15550000000');
      expect(rendered.to).toBe('+15551234567');
      expect(rendered.body).toContain('Order Confirmation: ');
      expect(rendered.body).toContain('Widget x2');
    });

    it('should truncate long messages with ellipsis', () => {
      const longBody = 'A'.repeat(200);
      const payload = makePayload({ body: longBody });
      const rendered = adapter.formatMessage(payload);

      expect(rendered.body.length).toBeLessThanOrEqual(160);
      expect(rendered.body).toContain('...');
    });

    it('should respect custom maxMessageLength', () => {
      const customAdapter = new SmsNotificationAdapter(
        { ...defaultConfig, maxMessageLength: 50 },
        transport,
      );
      const payload = makePayload({ body: 'A'.repeat(100) });
      const rendered = customAdapter.formatMessage(payload);

      expect(rendered.body.length).toBeLessThanOrEqual(50);
    });

    it('should not truncate short messages', () => {
      const payload = makePayload({ subject: 'Hi', body: 'Hello' });
      const rendered = adapter.formatMessage(payload);

      expect(rendered.body).toBe('Hi: Hello');
    });
  });

  describe('send', () => {
    it('should send a valid notification and return success', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('sms');
      expect(result.deliveredAt).toBeInstanceOf(Date);

      const sent = transport.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.from).toBe('+15550000000');
    });

    it('should trim recipient phone number before sending', async () => {
      const payload = makePayload({ recipient: '  +15551234567  ' });
      await adapter.send(payload);

      const sent = transport.getSentMessages();
      expect(sent[0]?.to).toBe('+15551234567');
    });

    it('should return failure for invalid recipient', async () => {
      const payload = makePayload({ recipient: 'not-a-number' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(transport.getSentMessages()).toHaveLength(0);
    });

    it('should return failure for empty recipient', async () => {
      const payload = makePayload({ recipient: '' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('cannot be empty');
    });

    it('should return failure when transport throws', async () => {
      const failingTransport: SmsTransport = {
        send: async () => {
          throw new Error('SMS gateway unavailable');
        },
      };
      const failAdapter = new SmsNotificationAdapter(defaultConfig, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS gateway unavailable');
    });
  });

  describe('getSentMessages / clearSentMessages', () => {
    it('should return sent messages from in-memory transport', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should return empty array when using non-InMemory transport', () => {
      const customTransport: SmsTransport = {
        send: async () => ({ messageId: 'x' }),
      };
      const customAdapter = new SmsNotificationAdapter(defaultConfig, customTransport);
      expect(customAdapter.getSentMessages()).toEqual([]);
    });
  });

  describe('getTransport', () => {
    it('should return the underlying transport', () => {
      expect(adapter.getTransport()).toBe(transport);
    });
  });
});

